import { Command, flags } from '@heroku-cli/command';
import * as color from '@heroku/heroku-cli-util/color';
import { ux } from '@oclif/core/ux';
export default class Leave extends Command {
    static aliases = ['leave'];
    static description = 'remove yourself from a team app';
    static example = `${color.command('heroku apps:leave -a APP')}`;
    static flags = {
        app: flags.app({ required: true }),
        remote: flags.remote(),
    };
    static topic = 'apps';
    async run() {
        const { flags } = await this.parse(Leave);
        const { app } = flags;
        const request = await this.heroku.get('/account');
        ux.action.start(`Leaving ${color.app(app)}`);
        const { body: account } = request;
        await this.heroku.delete(`/apps/${app}/collaborators/${encodeURIComponent(account.email)}`);
        ux.action.stop();
    }
}
